import React from "react";
import styled from "styled-components";

import IntroPanel from "./intro";
import WorkPanel from "./work";
import ProjectsPanel from "./projects";
import AboutPanel from "./about";
import Footer from "./footer";

import ColorButton from "./color_button";
import ResumeButton from "./resume_button";

// TODO: Make color appear via scroll
// TODO: ^^ or make child components color their respective panels (i.e. if they hover over title but not the panel)

class Main extends React.Component {
  constructor(props) {
    super(props);
  }

  render() {
    const childrenWithProps = React.Children.map(
      this.props.children,
      (child) => {
        if (React.isValidElement(child)) {
          return React.cloneElement(child, { colors: this.props.colors });
        }
        return child;
      }
    );

    return (
      <MainContainer color={this.props.colors.main}>
        {childrenWithProps}
      </MainContainer>
    );
  }
}

class App extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      colors: {
        main: "#ffffff",
        panel: "#b5feff",
        button: "#ffffff",
        heading: "#2f7fc4",
        text: "#1c1c1c",
        text_highlight: "#ffb429",
      },
    };
  }

  randomizeColors = (e) => {
    e.preventDefault();
    console.log("randomizing the color scheme!");
  };

  render() {
    return (
      <Main colors={this.state.colors}>
        <ColorButton clickHandler={this.randomizeColors} />
        <IntroPanel />
        <AboutPanel />
        <WorkPanel />
        <ProjectsPanel />
        <Footer />
      </Main>
    );
  }
}

export default App;

const MainContainer = styled.div`
  display: flex;
  flex-direction: column;
  align-items: center;
  height: 100%;
  width: 100%;
  background: ${(props) => props.color};
  transition: all 0.8s ease-in;
  * {
    transition: all 0.8s ease-in;
  }
`;
